import React from "react"
import TimelineYears from "../timeline/years"
import TimelineEvent from "../timeline/event"
import JSONData from "../../data/timeline.json"

const timelineLayout = () => (
    <div id="life">
        <div id="life-events">
            <div id="life-years" className="comment_">
                <TimelineYears year={2020} />
                {JSONData.event.map((data, index) => {
                        return <TimelineEvent date={data.date} title={data.title} />
                    })}
            </div>
        </div>
    </div>
)

export default timelineLayout